  1	import { useCallback, useEffect, useMemo, useRef } from "react";
  2	
  3	import type { NonDeletedExcalidrawElement } from "@excalidraw/element/types";
  4	
  5	import { useAtom } from "../../../editor-jotai";
  6	
  7	import { chatHistoryAtom, errorAtom, showPreviewAtom } from "../TTDContext";
  8	import { convertMermaidToExcalidraw } from "../common";
  9	import { isValidMermaidSyntax } from "../utils/mermaidValidation";
 10	
 11	import { getLastAssistantMessage } from "../utils/chat";
 12	
 13	import { useUIAppState } from "../../../context/ui-appState";
 14	
 15	import type { BinaryFiles } from "../../../types";
 16	import type { MermaidToExcalidrawLibProps } from "../types";
 17	
 18	const FAST_THROTTLE_DELAY = 300;
 19	const SLOW_THROTTLE_DELAY = 3000;
 20	const RENDER_SPEED_THRESHOLD = 100;
 21	const PARSE_FAIL_DELAY = 100;
 22	
 23	interface UseMermaidRendererProps {
 24	  mermaidToExcalidrawLib: MermaidToExcalidrawLibProps;
 25	  canvasRef: React.RefObject<HTMLDivElement | null>;
 26	}
 27	
 28	export const useMermaidRenderer = ({
 29	  mermaidToExcalidrawLib,
 30	  canvasRef,
 31	}: UseMermaidRendererProps) => {
 32	  const [chatHistory] = useAtom(chatHistoryAtom);
 33	  const [, setError] = useAtom(errorAtom);
 34	
 35	  const [showPreview, setShowPreview] = useAtom(showPreviewAtom);
 36	  const isRenderingRef = useRef(false);
 37	
 38	  const lastAssistantMessage = useMemo(
 39	    () => getLastAssistantMessage(chatHistory),
 40	    [chatHistory],
 41	  );
 42	
 43	  // Keeping lastAssistantMesssage in ref, so I can access it in useEffect hooks
 44	  const lastAssistantMessageRef = useRef(lastAssistantMessage);
 45	  useEffect(() => {
 46	    lastAssistantMessageRef.current = lastAssistantMessage;
 47	  }, [lastAssistantMessage]);
 48	
 49	  const data = useRef<{
 50	    elements: readonly NonDeletedExcalidrawElement[];
 51	    files: BinaryFiles | null;
 52	  }>({
 53	    elements: [],
 54	    files: null,
 55	  });
 56	
 57	  const lastRenderTimeRef = useRef(0);
 58	  const pendingContentRef = useRef<string | null>(null);
 59	  const hasErrorOffsetRef = useRef(false);
 60	  const currentThrottleDelayRef = useRef(FAST_THROTTLE_DELAY);
 61	
 62	  const { theme } = useUIAppState();
 63	
 64	  const renderMermaid = useCallback(
 65	    async (mermaidDefinition: string): Promise<boolean> => {
 66	      if (!mermaidDefinition.trim() || !mermaidToExcalidrawLib.loaded) {
 67	        return false;
 68	      }
 69	
 70	      if (isRenderingRef.current) {
 71	        return false;
 72	      }
 73	
 74	      isRenderingRef.current = true;
 75	
 76	      const renderStartTime = performance.now();
 77	
 78	      const result = await convertMermaidToExcalidraw({
 79	        canvasRef,
 80	        data,
 81	        mermaidToExcalidrawLib,
 82	        setError,
 83	        mermaidDefinition,
 84	        theme,
 85	      });
 86	
 87	      const renderDuration = performance.now() - renderStartTime;
 88	
 89	      if (renderDuration < RENDER_SPEED_THRESHOLD) {
 90	        currentThrottleDelayRef.current = FAST_THROTTLE_DELAY;
 91	      } else {
 92	        currentThrottleDelayRef.current = SLOW_THROTTLE_DELAY;
 93	      }
 94	
 95	      isRenderingRef.current = false;
 96	      return result.success;
 97	    },
 98	    [canvasRef, mermaidToExcalidrawLib, setError, theme],
 99	  );
100	
101	  const throttledRenderMermaid = useMemo(() => {
102	    const fn = async (content: string) => {
103	      const now = Date.now();
104	      const timeSinceLastRender = now - lastRenderTimeRef.current;
105	      const throttleDelay = currentThrottleDelayRef.current;
106	
107	      if (!isValidMermaidSyntax(content)) {
108	        if (!hasErrorOffsetRef.current) {
109	          lastRenderTimeRef.current = Math.max(
110	            lastRenderTimeRef.current,
111	            now - throttleDelay + PARSE_FAIL_DELAY,
112	          );
113	          hasErrorOffsetRef.current = true;
114	        }
115	        pendingContentRef.current = content;
116	        return;
117	      }
118	
119	      hasErrorOffsetRef.current = false;
120	
121	      if (timeSinceLastRender < throttleDelay) {
122	        pendingContentRef.current = content;
123	        return;
124	      }
125	
126	      pendingContentRef.current = null;
127	      const success = await renderMermaid(content);
128	      lastRenderTimeRef.current = Date.now();
129	
130	      if (!success) {
131	        lastRenderTimeRef.current =
132	          lastRenderTimeRef.current - throttleDelay + PARSE_FAIL_DELAY;
133	        hasErrorOffsetRef.current = true;
134	      }
135	    };
136	
137	    fn.flush = async () => {
138	      if (pendingContentRef.current) {
139	        const content = pendingContentRef.current;
140	        pendingContentRef.current = null;
141	        await renderMermaid(content);
142	        lastRenderTimeRef.current = Date.now();
143	      }
144	    };
145	
146	    fn.cancel = () => {
147	      pendingContentRef.current = null;
148	    };
149	
150	    return fn;
151	  }, [renderMermaid]);
152	
153	  const resetThrottleState = useCallback(() => {
154	    lastRenderTimeRef.current = 0;
155	    pendingContentRef.current = null;
156	    hasErrorOffsetRef.current = false;
157	    currentThrottleDelayRef.current = FAST_THROTTLE_DELAY;
158	  }, []);
159	
160	  // this hook is responsible for keep rendering during streaming
161	  useEffect(() => {
162	    if (lastAssistantMessage?.content && lastAssistantMessage?.isGenerating) {
163	      throttledRenderMermaid(lastAssistantMessage.content);
164	    } else if (!lastAssistantMessage?.isGenerating) {
165	      throttledRenderMermaid.flush();
166	      resetThrottleState();
167	      if (lastAssistantMessage?.content) {
168	        throttledRenderMermaid(lastAssistantMessage.content);
169	      }
170	    }
171	  }, [
172	    resetThrottleState,
173	    throttledRenderMermaid,
174	    lastAssistantMessage?.isGenerating,
175	    lastAssistantMessage?.content,
176	  ]);
177	
178	  // render the last message if the user navigates between the existing chats
179	  useEffect(() => {
180	    const msg = lastAssistantMessageRef.current;
181	    if (!msg?.content || msg.error) {
182	      return;
183	    }
184	
185	    if (!showPreview) {
186	      return;
187	    }
188	
189	    renderMermaid(msg.content);
190	  }, [chatHistory?.id, renderMermaid, showPreview]);
191	
192	  useEffect(() => {
193	    if (
194	      !chatHistory.messages?.filter((msg) => msg.type === "assistant").length
195	    ) {
196	      const canvasNode = canvasRef.current;
197	      if (canvasNode) {
198	        const parent = canvasNode.parentElement;
199	        if (parent) {
200	          parent.style.background = "";
201	          canvasNode.replaceChildren();
202	        }
203	      }
204	      setShowPreview(false);
205	    } else if (!showPreview) {
206	      setShowPreview(true);
207	    }
208	  }, [chatHistory.messages, setShowPreview, canvasRef, showPreview]);
209	
210	  return {
211	    data,
212	  };
213	};

