  1	import { useCallback, useEffect, useRef } from "react";
  2	import { randomId } from "@excalidraw/common";
  3	
  4	import { atom, useAtom } from "../../editor-jotai";
  5	
  6	import { chatHistoryAtom } from "./TTDContext";
  7	
  8	import type { SavedChat, SavedChats, TTDPersistenceAdapter } from "./types";
  9	
 10	interface UseTTDChatStorageProps {
 11	  persistenceAdapter: TTDPersistenceAdapter;
 12	}
 13	
 14	interface UseTTDChatStorageReturn {
 15	  savedChats: SavedChats;
 16	  saveCurrentChat: () => Promise<void>;
 17	  deleteChat: (chatId: string) => Promise<SavedChats>;
 18	  restoreChat: (chat: SavedChat) => SavedChat;
 19	  createNewChatId: () => Promise<string>;
 20	}
 21	
 22	const generateChatTitle = (firstMessage: string): string => {
 23	  const trimmed = firstMessage.trim();
 24	  if (trimmed.length <= 50) {
 25	    return trimmed;
 26	  }
 27	  return `${trimmed.substring(0, 47)}...`;
 28	};
 29	
 30	// Shared atom for saved chats - starts empty, populated via onLoadChats
 31	export const savedChatsAtom = atom<SavedChats>([]);
 32	export const isLoadingChatsAtom = atom<boolean>(false);
 33	export const chatsLoadedAtom = atom<boolean>(false);
 34	
 35	export const useTTDChatStorage = ({
 36	  persistenceAdapter,
 37	}: UseTTDChatStorageProps): UseTTDChatStorageReturn => {
 38	  const [chatHistory] = useAtom(chatHistoryAtom);
 39	  const [savedChats, setSavedChats] = useAtom(savedChatsAtom);
 40	  const [isLoading, setIsLoading] = useAtom(isLoadingChatsAtom);
 41	  const [chatsLoaded, setChatsLoaded] = useAtom(chatsLoadedAtom);
 42	
 43	  // Ref to track latest savedChats for async operations
 44	  const savedChatsRef = useRef(savedChats);
 45	  savedChatsRef.current = savedChats;
 46	
 47	  const lastMessageInHistory =
 48	    chatHistory?.messages[chatHistory?.messages.length - 1];
 49	
 50	  // Load chats on-demand
 51	  const loadChats = useCallback(async () => {
 52	    if (chatsLoaded || isLoading) {
 53	      return;
 54	    }
 55	
 56	    setIsLoading(true);
 57	    try {
 58	      const chats = await persistenceAdapter.loadChats();
 59	      setSavedChats(chats);
 60	      setChatsLoaded(true);
 61	    } catch (error) {
 62	      console.warn("Failed to load chats:", error);
 63	      setSavedChats([]);
 64	      setChatsLoaded(true);
 65	    } finally {
 66	      setIsLoading(false);
 67	    }
 68	  }, [
 69	    chatsLoaded,
 70	    isLoading,
 71	    setSavedChats,
 72	    setIsLoading,
 73	    setChatsLoaded,
 74	    persistenceAdapter,
 75	  ]);
 76	
 77	  // INITIAL LOAD
 78	  useEffect(() => {
 79	    loadChats();
 80	    // eslint-disable-next-line react-hooks/exhaustive-deps
 81	  }, []);
 82	
 83	  const saveCurrentChat = useCallback(async () => {
 84	    if (chatHistory.messages.length === 0) {
 85	      return;
 86	    }
 87	
 88	    const firstUserMessage = chatHistory.messages.find(
 89	      (msg) => msg.type === "user",
 90	    );
 91	    if (!firstUserMessage || typeof firstUserMessage.content !== "string") {
 92	      return;
 93	    }
 94	
 95	    const title = generateChatTitle(firstUserMessage.content);
 96	
 97	    const currentSavedChats = savedChatsRef.current;
 98	    const existingChat = currentSavedChats.find(
 99	      (chat) => chat.id === chatHistory.id,
100	    );
101	
102	    const messagesChanged =
103	      !existingChat ||
104	      existingChat.messages.length !== chatHistory.messages.length ||
105	      existingChat.messages.some(
106	        (msg, i) =>
107	          msg.id !== chatHistory.messages[i]?.id ||
108	          msg.content !== chatHistory.messages[i]?.content,
109	      );
110	
111	    const chatToSave: SavedChat = {
112	      id: chatHistory.id,
113	      title,
114	      messages: chatHistory.messages
115	        .filter((msg) => msg.type === "user" || msg.type === "assistant")
116	        .map((msg) => ({
117	          ...msg,
118	          timestamp:
119	            msg.timestamp instanceof Date
120	              ? msg.timestamp
121	              : new Date(msg.timestamp),
122	        })),
123	      currentPrompt: chatHistory.currentPrompt,
124	      timestamp: messagesChanged
125	        ? Date.now()
126	        : existingChat?.timestamp ?? Date.now(),
127	    };
128	
129	    const updatedChats = [
130	      ...currentSavedChats.filter((chat) => chat.id !== chatHistory.id),
131	      chatToSave,
132	    ]
133	      .sort((a, b) => b.timestamp - a.timestamp)
134	      .slice(0, 10);
135	
136	    setSavedChats(updatedChats);
137	
138	    try {
139	      await persistenceAdapter.saveChats(updatedChats);
140	    } catch (error) {
141	      console.warn("Failed to save chats:", error);
142	    }
143	  }, [chatHistory, setSavedChats, persistenceAdapter]);
144	
145	  // Auto-save when generation completes
146	  useEffect(() => {
147	    if (!lastMessageInHistory?.isGenerating) {
148	      saveCurrentChat();
149	    }
150	    // eslint-disable-next-line react-hooks/exhaustive-deps
151	  }, [
152	    chatHistory.messages?.length,
153	    lastMessageInHistory?.id,
154	    lastMessageInHistory?.isGenerating,
155	  ]);
156	
157	  const deleteChat = useCallback(
158	    async (chatId: string): Promise<SavedChats> => {
159	      const updatedChats = savedChatsRef.current.filter(
160	        (chat) => chat.id !== chatId,
161	      );
162	      setSavedChats(updatedChats);
163	
164	      try {
165	        await persistenceAdapter.saveChats(updatedChats);
166	      } catch (error) {
167	        console.warn("Failed to save after delete:", error);
168	      }
169	
170	      return updatedChats;
171	    },
172	    [setSavedChats, persistenceAdapter],
173	  );
174	
175	  const restoreChat = useCallback((chat: SavedChat): SavedChat => {
176	    // Save is handled by the caller after state update
177	    return chat;
178	  }, []);
179	
180	  const createNewChatId = useCallback(async (): Promise<string> => {
181	    await saveCurrentChat();
182	    return randomId();
183	  }, [saveCurrentChat]);
184	
185	  return {
186	    savedChats,
187	    saveCurrentChat,
188	    deleteChat,
189	    restoreChat,
190	    createNewChatId,
191	  };
192	};

