 12	import type { ExcalidrawImperativeAPI } from "@excalidraw/excalidraw/types";
 13	
 14	import { TTDIndexedDBAdapter } from "../data/TTDStorage";
 15	
 16	export const AIComponents = ({
 17	  excalidrawAPI,
 18	}: {
 19	  excalidrawAPI: ExcalidrawImperativeAPI;
 20	}) => {
 21	  return (
 22	    <>
 23	      <DiagramToCodePlugin
 24	        generate={async ({ frame, children }) => {
 25	          const appState = excalidrawAPI.getAppState();
 26	
 27	          const blob = await exportToBlob({
 28	            elements: children,
 29	            appState: {
 30	              ...appState,
 31	              exportBackground: true,
 32	              viewBackgroundColor: appState.viewBackgroundColor,
 33	            },
 34	            exportingFrame: frame,
 35	            files: excalidrawAPI.getFiles(),
 36	            mimeType: MIME_TYPES.jpg,
 37	          });
 38	
 39	          const dataURL = await getDataURL(blob);
 40	
 41	          const textFromFrameChildren = getTextFromElements(children);
 42	
 43	          const response = await fetch(
 44	            `${
 45	              import.meta.env.VITE_APP_AI_BACKEND
 46	            }/v1/ai/diagram-to-code/generate`,
 47	            {
 48	              method: "POST",
 49	              headers: {
 50	                Accept: "application/json",
 51	                "Content-Type": "application/json",
 52	              },
 53	              body: JSON.stringify({
 54	                texts: textFromFrameChildren,
 55	                image: dataURL,
 56	                theme: appState.theme,
 57	              }),
 58	            },
 59	          );
 60	
 61	          if (!response.ok) {
 62	            const text = await response.text();
 63	            const errorJSON = safelyParseJSON(text);
 64	
 65	            if (!errorJSON) {
 66	              throw new Error(text);
 67	            }
 68	
 69	            if (errorJSON.statusCode === 429) {
 70	              return {
 71	                html: `<html>
 72	                <body style="margin: 0; text-align: center">
 73	                <div style="display: flex; align-items: center; justify-content: center; flex-direction: column; height: 100vh; padding: 0 60px">
 74	                  <div style="color:red">Too many requests today,</br>please try again tomorrow!</div>
 75	                  </br>
 76	                  </br>
 77	                  <div>You can also try <a href="${
 78	                    import.meta.env.VITE_APP_PLUS_LP
 79	                  }/plus?utm_source=excalidraw&utm_medium=app&utm_content=d2c" target="_blank" rel="noopener">Excalidraw+</a> to get more requests.</div>
 80	                </div>
 81	                </body>
 82	                </html>`,
 83	              };
 84	            }
 85	
 86	            throw new Error(errorJSON.message || text);
 87	          }
 88	
 89	          try {
 90	            const { html } = await response.json();
 91	
 92	            if (!html) {
 93	              throw new Error("Generation failed (invalid response)");
 94	            }
 95	            return {
 96	              html,
 97	            };
 98	          } catch (error: any) {
 99	            throw new Error("Generation failed (invalid response)");
100	          }
101	        }}
102	      />
103	
104	      <TTDDialog
105	        onTextSubmit={async (props) => {
106	          const { onChunk, onStreamCreated, signal, messages } = props;
107	
108	          const result = await TTDStreamFetch({
