111	            }/v1/ai/text-to-diagram/chat-streaming`,
112	            messages,
113	            onChunk,
114	            onStreamCreated,
115	            extractRateLimits: true,
116	            signal,
117	          });
118	
119	          return result;
120	        }}
121	        persistenceAdapter={TTDIndexedDBAdapter}
122	      />
123	    </>
124	  );
